namespace sv_f98bc86e5d9044b1ab8fe119ff7af077.Models;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@page "/board"
@using sv_f98bc86e5d9044b1ab8fe119ff7af077.Models
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h1>Project Board</h1>

@if (_loading)
{
    <p><em>Loading tasks...</em></p>
}
else if (_error is not null)
{
    <div class="alert alert-danger">@_error</div>
}
else
{
    <BoardStats Tasks="_allTasks" />
    <SearchBar SearchTerm="@_searchTerm" SearchTermChanged="OnSearchChanged" />

    <div class="kanban-board">
        @foreach (var column in _columns)
        {
            var tasks = GetFilteredTasksForStatus(column);
            <KanbanColumn ColumnName="@column"
                          Tasks="tasks"
                          OnMoveTask="HandleMoveTask"
                          OnCreateTask="HandleCreateTask"
                          IsFirst="@(column == _columns[0])"
                          IsLast="@(column == _columns[^1])"
                          Columns="_columns" />
        }
    </div>
}

@code {
    private List<TaskItem> _allTasks = new();
    private string _searchTerm = string.Empty;
    private bool _loading = true;
    private string? _error;

    private readonly string[] _columns = { "To Do", "In Progress", "Done" };

    protected override async Task OnInitializedAsync()
    {
        try
        {
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasksForStatus(string status)
    {
        return _allTasks
            .Where(t => t.Status == status)
            .Where(t => string.IsNullOrWhiteSpace(_searchTerm) ||
                        t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase))
            .ToList();
    }

    private void OnSearchChanged(string term)
    {
        _searchTerm = term;
    }

    private async Task HandleMoveTask(MoveTaskRequest request)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(request.TaskId, request.NewStatus);
            var index = _allTasks.FindIndex(t => t.Id == request.TaskId);
            if (index >= 0)
            {
                _allTasks[index] = _allTasks[index] with { Status = request.NewStatus };
            }
        }
        catch (Exception ex)
        {
            _error = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task HandleCreateTask(CreateTaskRequest request)
    {
        try
        {
            var newTask = await TaskService.CreateTaskAsync(
                request.Title, request.Assignee, request.Priority, request.DueDate);
            _allTasks.Add(newTask);
        }
        catch (Exception ex)
        {
            _error = $"Failed to create task: {ex.Message}";
        }
    }
}

@using sv_f98bc86e5d9044b1ab8fe119ff7af077.Models

<div class="board-stats">
    <span class="stat-item"><strong>Total:</strong> @Tasks.Count</span>
    <span class="stat-item"><strong>To Do:</strong> @Tasks.Count(t => t.Status == "To Do")</span>
    <span class="stat-item"><strong>In Progress:</strong> @Tasks.Count(t => t.Status == "In Progress")</span>
    <span class="stat-item"><strong>Done:</strong> @Tasks.Count(t => t.Status == "Done")</span>
    <span class="stat-item"><strong>Overdue:</strong> @Tasks.Count(t => t.DueDate < DateTime.Today)</span>
</div>

@code {
    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();
}

@using sv_f98bc86e5d9044b1ab8fe119ff7af077.Models

<div class="kanban-column">
    <div class="column-header">
        <h3>@ColumnName (@Tasks.Count)</h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      IsFirst="IsFirst"
                      IsLast="IsLast"
                      Columns="Columns"
                      CurrentColumn="ColumnName"
                      OnMoveTask="OnMoveTask" />
        }
    </div>

    @if (_showForm)
    {
        <AddTaskForm ColumnStatus="@ColumnName"
                     OnSave="HandleSave"
                     OnCancel="() => _showForm = false" />
    }
    else
    {
        <button class="btn-add-task" @onclick="() => _showForm = true">Add Task</button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnName { get; set; } = string.Empty;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter]
    public bool IsFirst { get; set; }

    [Parameter]
    public bool IsLast { get; set; }

    [Parameter]
    public string[] Columns { get; set; } = Array.Empty<string>();

    [Parameter]
    public EventCallback<MoveTaskRequest> OnMoveTask { get; set; }

    [Parameter]
    public EventCallback<CreateTaskRequest> OnCreateTask { get; set; }

    private bool _showForm;

    private async Task HandleSave(CreateTaskRequest request)
    {
        await OnCreateTask.InvokeAsync(request);
        _showForm = false;
    }
}

@using sv_f98bc86e5d9044b1ab8fe119ff7af077.Models

<div class="task-card">
    <div class="task-title">@Task.Title</div>
    <div class="task-assignee">@Task.Assignee</div>
    <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <div class="task-due-date">@Task.DueDate.ToString("MMM dd")</div>

    <div class="task-actions">
        @if (!IsFirst)
        {
            <button class="btn-move" @onclick="MoveLeft">Move Left</button>
        }
        @if (!IsLast)
        {
            <button class="btn-move" @onclick="MoveRight">Move Right</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool IsFirst { get; set; }

    [Parameter]
    public bool IsLast { get; set; }

    [Parameter]
    public string[] Columns { get; set; } = Array.Empty<string>();

    [Parameter]
    public string CurrentColumn { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<MoveTaskRequest> OnMoveTask { get; set; }

    private async Task MoveLeft()
    {
        var index = Array.IndexOf(Columns, CurrentColumn);
        if (index > 0)
        {
            await OnMoveTask.InvokeAsync(new MoveTaskRequest(Task.Id, Columns[index - 1]));
        }
    }

    private async Task MoveRight()
    {
        var index = Array.IndexOf(Columns, CurrentColumn);
        if (index < Columns.Length - 1)
        {
            await OnMoveTask.InvokeAsync(new MoveTaskRequest(Task.Id, Columns[index + 1]));
        }
    }
}

@using sv_f98bc86e5d9044b1ab8fe119ff7af077.Models

<div class="add-task-form">
    <input type="text" placeholder="Title" @bind="_title" />
    <input type="text" placeholder="Assignee" @bind="_assignee" />
    <select @bind="_priority">
        <option value="High">High</option>
        <option value="Medium">Medium</option>
        <option value="Low">Low</option>
    </select>
    <input type="date" @bind="_dueDate" />
    <div class="form-actions">
        <button class="btn-save" @onclick="Save">Save</button>
        <button class="btn-cancel" @onclick="Cancel">Cancel</button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public string ColumnStatus { get; set; } = string.Empty;

    [Parameter]
    public EventCallback<CreateTaskRequest> OnSave { get; set; }

    [Parameter]
    public EventCallback OnCancel { get; set; }

    private string _title = string.Empty;
    private string _assignee = string.Empty;
    private string _priority = "Medium";
    private DateTime _dueDate = DateTime.Today;

    private async Task Save()
    {
        if (!string.IsNullOrWhiteSpace(_title))
        {
            await OnSave.InvokeAsync(new CreateTaskRequest(_title, _assignee, _priority, _dueDate, ColumnStatus));
        }
    }

    private async Task Cancel()
    {
        await OnCancel.InvokeAsync();
    }
}

